// Typical Express project structure:
//
// my-app/
// ├── src/
// │   ├── index.js              # App entry point
// │   ├── app.js                # Express app configuration
// │   ├── routes/
// │   │   ├── index.js           # Route aggregator
// │   │   └── users.routes.js    # User routes
// │   ├── controllers/
// │   │   └── users.controller.js
// │   ├── services/
// │   │   └── users.service.js
// │   ├── models/
// │   │   └── user.model.js
// │   ├── middleware/
// │   │   ├── auth.js
// │   │   └── errorHandler.js
// │   ├── utils/
// │   │   └── logger.js
// │   └── config/
// │       └── index.js
// ├── package.json
// ├── .env
// └── .gitignore

// --- src/app.js ---
const express = require('express');
const routes = require('./routes');

const app = express();

app.use(express.json());
app.use('/api', routes);

module.exports = app;

// --- routes/users.routes.js ---
const express = require('express');
const router = express.Router();
const usersController = require('../controllers/users.controller');

router.get('/', usersController.getAllUsers);
router.get('/:id', usersController.getUserById);
router.post('/', usersController.createUser);

module.exports = router;

// --- controllers/users.controller.js ---
const usersService = require('../services/users.service');

exports.getAllUsers = (req, res) => {
  const users = usersService.getAll();
  res.json(users);
};

exports.getUserById = (req, res) => {
  const user = usersService.getById(parseInt(req.params.id));
  if (!user) return res.status(404).json({ error: 'User not found' });
  res.json(user);
};

exports.createUser = (req, res) => {
  const user = usersService.create(req.body);
  res.status(201).json(user);
};

// --- services/users.service.js ---
let users = [{ id: 1, name: 'Alice', email: 'alice@example.com' }];
let nextId = 2;

exports.getAll = () => users;

exports.getById = (id) => users.find(u => u.id === id);

exports.create = (data) => {
  const user = { id: nextId++, name: data.name, email: data.email };
  users.push(user);
  return user;
};

// --- src/app.js (Express configuration) ---
const express = require('express');
const cors = require('cors');
const usersRoutes = require('./routes/users.routes');
const errorHandler = require('./middleware/errorHandler');

const app = express();

// Global middleware
app.use(cors());
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// Routes
app.use('/api/users', usersRoutes);

// Error handling (must be last)
app.use(errorHandler);

module.exports = app;

// --- src/index.js (Server startup) ---
const app = require('./app');
const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

// --- middleware/errorHandler.js ---
module.exports = (err, req, res, next) => {
  console.error(err.stack);
  res.status(err.status || 500).json({
    error: err.message || 'Internal Server Error'
  });
};

